import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { HouseholdService } from '../../services/household.service';
import { Household } from '../../models/models';

@Component({
  selector: 'app-nav',
  templateUrl: './nav.component.html',
  styleUrls: ['./nav.component.css']
})
export class NavComponent implements OnInit {
  households: Household[] = [];
  selectedHousehold: Household | null = null;

  constructor(
    public authService: AuthService,
    private householdService: HouseholdService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.loadHouseholds();
    this.householdService.selectedHousehold$.subscribe(h => {
      this.selectedHousehold = h;
    });
  }

  loadHouseholds(): void {
    this.householdService.getAll().subscribe({
      next: res => {
        this.households = res.results;
        if (!this.selectedHousehold && this.households.length > 0) {
          this.householdService.selectHousehold(this.households[0]);
        }
      }
    });
  }

  selectHousehold(h: Household): void {
    this.householdService.selectHousehold(h);
  }

  logout(): void {
    this.authService.logout().subscribe({
      next: () => this.router.navigate(['/login']),
      error: () => {
        this.authService.clearSession();
        this.router.navigate(['/login']);
      }
    });
  }
}
<nav class="navbar">
  <div class="nav-container">
    <a routerLink="/dashboard" class="nav-brand">
      Pantry Helper
    </a>

    <!-- household selector -->
    <div class="household-selector" *ngIf="households.length > 0">
      <select (change)="selectHousehold(households[$any($event.target).value])">
        <option *ngFor="let h of households; let i = index" [value]="i"
          [selected]="selectedHousehold?.id === h.id">
          {{ h.name }}
        </option>
      </select>
    </div>

    <!-- nav links -->
    <div class="nav-links">
      <a routerLink="/dashboard" routerLinkActive="active">Dashboard</a>
      <a routerLink="/pantry" routerLinkActive="active">Pantry</a>
      <a routerLink="/recipes" routerLinkActive="active">Recipes</a>
      <a routerLink="/households" routerLinkActive="active">Households</a>
    </div>

    <!--user -->
    <div class="nav-user">
      <a routerLink="/profile" class="user-btn">
        {{ authService.currentUser?.username }}
      </a>
      <button class="btn btn-sm btn-secondary" (click)="logout()">Logout</button>
    </div>

  </div>
</nav>
